        TelemetryBatchResponseDto response = new TelemetryBatchResponseDto();
        response.batchId = request == null ? null : request.batchId;
        response.status = "INGEST_INTERFACE_READY_E2_PENDING";
        response.accepted = false;
        response.persisted = false;
        response.ingestStage = "E2_REHEALTH_INGEST_SERVICE_REQUIRED";
        response.measurementCount = request == null || request.measurements == null ? 0 : request.measurements.size();
        response.rejectedCount = 0;
        response.warnings.add("hardware_db persistence and MQ-backed ingestion are intentionally deferred to E2");
        return response;
    }
}

